#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=510,Mod=1e9+7;int dp[N][N],n,g[N][N];bool a[N][N];
int main()
{
	n=read();rep(1,n,i)rep(1,n,j)a[i][j]=read();
	rep(1,n,i)dp[i][i]=g[i][i]=1,dp[i][i+1]=g[i][i+1]=a[i][i+1];
	for(int T=3;T<=n;++T)for(int l=1,r=T;r<=n;++l,++r)
	{
		for(int k=l+1;k<r;++k)dp[l][r]=(1ll*dp[l][k]*g[k][r]+dp[l][r])%Mod;
		if(a[l][r])
		{
			for(int k=l;k<r;++k)
			{
				g[l][r]=(1ll*dp[l][k]*dp[k+1][r]+g[l][r])%Mod;
				dp[l][r]=(1ll*dp[l][k]*dp[k+1][r]+dp[l][r])%Mod;
			}
		}
	}
	printf("%d\n",dp[1][n]);return 0;
}
